import {RecordingType} from "@recordings/Domain/Entities/RecordingEntity.ts";

export enum RecordingTier {
    FREE = 0,
    PREMIUM = 1,
    DISCOUNT_FOR_MEMBERS = 2
}

export interface RecordingDto {
    id: string;
    name: string;
    description: string;
    type: RecordingType;
    tier: RecordingTier;
}

import { RecordingType, RecordingTier } from "@recordings/Domain/Entities/RecordingEntity.ts";

export { RecordingTier };

export interface RecordingDto {
    id: string;
    name: string;
    description: string;
    type: RecordingType;
    tier: RecordingTier;
}

import {RecordingEntity} from "@recordings/Domain/Entities/RecordingEntity.ts";
import {RecordingDto, RecordingTier} from "@recordings/Data/Entities/RecordingDto.ts";

export default class RecordingEntityMapper {

    public ToDomain(dto: RecordingDto): RecordingEntity {

        return {
            Name : dto.name,
            Type: dto.type,
            Id: dto.id,
            Description: dto.description,
        };
    }

    public ToDto(entity: RecordingEntity): RecordingDto {
        return {
            name: entity.Name,
            type: entity.Type,
            tier: RecordingTier.FREE,
            id: entity.Id,
            description: entity.Description,
        };
    }

}

import {RecordingEntity, RecordingTier} from "@recordings/Domain/Entities/RecordingEntity.ts";
import {RecordingDto} from "@recordings/Data/Entities/RecordingDto.ts";

export default class RecordingEntityMapper {

    public ToDomain(dto: RecordingDto): RecordingEntity {

        return {
            Name : dto.name,
            Type: dto.type,
            Id: dto.id,
            Description: dto.description,
            Tier: dto.tier,
        };
    }

    public ToDto(entity: RecordingEntity): RecordingDto {
        return {
            name: entity.Name,
            type: entity.Type,
            tier: entity.Tier ?? RecordingTier.FREE,
            id: entity.Id,
            description: entity.Description,
        };
    }

}

export enum RecordingType {
    MEDITACION,
    MASTERCLASS,
    TALLER,
}

