    &:hover {
        box-shadow: vars.$shadow-lg;
        transform: translateY(-2px);
    }

    &__premium-badge {
        display: inline-flex;
        align-items: center;
        gap: vars.$space-1;
        font-size: 0.7rem;
        font-weight: 600;
        text-transform: uppercase;
        letter-spacing: 0.05em;
        color: vars.$color-primary;
        border: 1px solid rgba(vars.$color-primary, 0.4);
        border-radius: vars.$radius-full;
        padding: vars.$space-1 vars.$space-2;
        margin-bottom: vars.$space-3;
    }

    &__content {
        margin-bottom: vars.$space-6;
    }

    &__title {
        font-family: fonts.$font-primary;
        font-size: fonts.$font-size-xl;
        color: vars.$color-dark;
        margin-bottom: vars.$space-3;
        font-weight: fonts.$font-weight-bold;
    }

    &__description {
        font-size: fonts.$font-size-md;
        color: vars.$color-dark-muted;
        line-height: 1.6;
        margin: 0;
    }

    &__footer {
        margin-top: auto;
    }

    &__button {
        display: flex;
        justify-content: center;
        align-items: center;
        gap: vars.$space-2;

        &--disabled {
            background-color: vars.$color-primary !important;
            color: vars.$color-primary-light !important;
            border-color: vars.$color-primary !important;
            opacity: 0.8;
        }
    }
}

import React from "react";
import { RecordingEntity } from "@recordings/Domain/Entities/RecordingEntity";
import PrimaryButton from "@core/Presentation/Components/atoms/PrimaryButton/PrimaryButton";
import "./RecordingCard.scss";
import { Play } from "lucide-react";

interface RecordingCardProps {
    recording: RecordingEntity;
    isAuthenticated: boolean;
    onPlay: (recording: RecordingEntity) => void;
    isLoadingUrl?: boolean;
}

const RecordingCard: React.FC<RecordingCardProps> = ({
    recording,
    isAuthenticated,
    onPlay,
    isLoadingUrl = false
}) => {
    return (
        <div className="recording-card vh-surface-card">
            <div className="recording-card__content">
                <h3 className="recording-card__title">{recording.Name}</h3>
                <p className="recording-card__description">{recording.Description}</p>
            </div>

            <div className="recording-card__footer">
                <PrimaryButton
                    variant="primary"
                    label={isAuthenticated ? "Ver grabación" : "Solo usuarios registrados"}
                    disabled={!isAuthenticated || isLoadingUrl}
                    trackId={`reproducir_grabacion_${recording.Name}`}
                    iconLeft={<Play />}
                    onClick={() => isAuthenticated && onPlay(recording)}
                    fullWidth
                />
            </div>
        </div>
    );
};

export default RecordingCard;

import React from "react";
import { RecordingEntity, RecordingTier } from "@recordings/Domain/Entities/RecordingEntity";
import PrimaryButton from "@core/Presentation/Components/atoms/PrimaryButton/PrimaryButton";
import "./RecordingCard.scss";
import { Play, Star } from "lucide-react";
import { useTranslation } from "react-i18next";

interface RecordingCardProps {
    recording: RecordingEntity;
    isAuthenticated: boolean;
    hasActiveSubscription: boolean;
    onPlay: (recording: RecordingEntity) => void;
    onSubscribe: () => void;
    isLoadingUrl?: boolean;
    isSubscribeLoading?: boolean;
}

const RecordingCard: React.FC<RecordingCardProps> = ({
    recording,
    isAuthenticated,
    hasActiveSubscription,
    onPlay,
    onSubscribe,
    isLoadingUrl = false,
    isSubscribeLoading = false,
}) => {
    const { t } = useTranslation();
    const isPremium = recording.Tier === RecordingTier.PREMIUM || recording.Tier === RecordingTier.DISCOUNT_FOR_MEMBERS;
    const needsSubscription = isAuthenticated && isPremium && !hasActiveSubscription;

    const getButtonConfig = () => {
        if (!isAuthenticated) {
            return {
                label: t("pages.recordings.card.restricted"),
                disabled: true,
                icon: <Play />,
                onClick: () => {},
            };
        }
        if (needsSubscription) {
            return {
                label: isSubscribeLoading ? t("pages.recordings.card.subscribe_loading") : t("pages.recordings.card.subscribe"),
                disabled: isSubscribeLoading,
                icon: <Star />,
                onClick: onSubscribe,
            };
        }
        return {
            label: t("pages.recordings.card.watch"),
            disabled: isLoadingUrl,
            icon: <Play />,
            onClick: () => onPlay(recording),
        };
    };

    const btnConfig = getButtonConfig();

    return (
        <div className="recording-card vh-surface-card">
            <div className="recording-card__content">
                {isPremium && (
                    <span className="recording-card__premium-badge">
                        <Star size={12} /> Premium
                    </span>
                )}
                <h3 className="recording-card__title">{recording.Name}</h3>
                <p className="recording-card__description">{recording.Description}</p>
            </div>

            <div className="recording-card__footer">
                <PrimaryButton
                    variant={needsSubscription ? "secondary" : "primary"}
                    label={btnConfig.label}
                    disabled={btnConfig.disabled}
                    trackId={`recording_action_${recording.Id}`}
                    iconLeft={btnConfig.icon}
                    onClick={btnConfig.onClick}
                    fullWidth
                />
            </div>
        </div>
    );
};

export default RecordingCard;
